func (c *LRUCache) evict() {
	for c.currentSize > c.maxSize {
		oldest := c.list.Back()
		if oldest == nil {
			break
		}
		entry := oldest.Value.(*cacheEntry)
		c.list.Remove(oldest)
		delete(c.items, entry.key)
		c.currentSize -= entry.size
		c.evictionCount++
		if c.onEvict != nil {
			c.onEvict(entry.key, entry.value)
		}
	}
}
